#!/usr/bin/env node
// Map legacy scientific infographics into the new (19-30) article folders
// as their middle image. Converts .jpg sources to .webp for consistency.
//
// Each new article keeps its own _1.webp (top, AI-generated by user) and gets
// _2.webp from the legacy library matching its topic.

import { readFile, writeFile, copyFile, access } from 'node:fs/promises'
import path from 'node:path'
import sharp from 'sharp'

const ROOT = path.resolve(path.dirname(new URL(import.meta.url).pathname).replace(/^\/([A-Za-z]:)/, '$1'), '..')
const LEGACY_DIR = path.join(ROOT, 'public', 'images', 'blog', 'Old articles')
const BLOG_DIR = path.join(ROOT, 'public', 'images', 'blog')

// Mapping: article number -> legacy infographic file
const MAPPING = [
  { n: 19, slug: 'biosaccharide-gum-1-explained-the-hidden-hero-of-sensitive-skincare', legacy: 'peptides-for-skin-barrier-repair-2.webp' },
  { n: 20, slug: 'what-is-transepidermal-water-loss-and-why-it-matters-after-a-procedure', legacy: 'skin-feels-tight-after-procedure-2.webp' },
  { n: 21, slug: 'why-sensitive-skin-reacts-to-aesthetic-procedures-and-how-to-manage-it', legacy: 'aftercare-mistakes-ruin-procedure-results-2.webp' },
  { n: 22, slug: 'how-to-build-a-long-term-anti-aging-routine-around-aesthetic-treatments', legacy: 'post-procedure-skincare-routine-2.webp' },
  { n: 23, slug: 'what-to-know-about-combining-microneedling-with-exosome-therapy', legacy: 'plant-exosomes-skincare-2.webp' },
  { n: 24, slug: 'is-it-safe-to-use-active-ingredients-between-procedure-sessions', legacy: 'when-can-i-use-retinol-after-microneedling-laser-2.webp' },
  { n: 25, slug: 'how-to-travel-safely-after-an-aesthetic-procedure-a-recovery-checklist', legacy: 'sun-exposure-after-aesthetic-procedures-why-spf-is-non-negotiable-2.jpg' },
  { n: 26, slug: 'how-stress-affects-post-procedure-skin-healing', legacy: 'nad-plus-for-skin-2.webp' },
  { n: 27, slug: 'what-to-do-on-the-morning-of-your-aesthetic-procedure-a-skin-prep-guide', legacy: 'standardized-aftercare-protocols-clinics-2.webp' },
  { n: 28, slug: 'why-you-should-avoid-hot-showers-after-microneedling-and-laser', legacy: 'preventing-hyperpigmentation-after-aesthetic-procedures-2.webp' },
  { n: 29, slug: 'how-to-tell-if-your-skin-barrier-has-recovered-after-a-procedure', legacy: 'chemical-peel-aftercare-2.webp' },
  { n: 30, slug: 'how-to-choose-a-post-procedure-serum-a-complete-buyers-guide', legacy: 'pdrn-in-skincare-2.webp' },
]

async function fileExists(p) { try { await access(p); return true } catch { return false } }

for (const item of MAPPING) {
  const folderName = `Article ${item.n} - ${item.slug}`
  const folder = path.join(BLOG_DIR, folderName)
  const legacySrc = path.join(LEGACY_DIR, item.legacy)
  const dst = path.join(folder, `${folderName}_2.webp`)

  if (!(await fileExists(legacySrc))) {
    console.warn(`[skip] Article ${item.n}: legacy file not found: ${item.legacy}`)
    continue
  }

  if (item.legacy.endsWith('.webp')) {
    await copyFile(legacySrc, dst)
  } else {
    await sharp(legacySrc).webp({ quality: 88 }).toFile(dst)
  }
  console.log(`Article ${item.n}  <-  ${item.legacy}`)
}

console.log('\nDone. All middle images placed into per-article folders as _2.webp.')
